let boardState = {
  cards: [{ id: 'card-2', columnId: 'col-1' }],
  columns: [
    { id: 'col-1', cardOrderIds: ['card-1', 'card-2'] },
    { id: 'col-2', cardOrderIds: ['card-3'] }
  ]
};
const activeCardId = 'card-2';
const overColumnId = 'col-2';
const overCardId = 'card-3';

// Logic cập nhật UI lạc quan
const oldColumn = boardState.columns.find(c => c.cardOrderIds.includes(activeCardId));
const newColumn = boardState.columns.find(c => c.id === overColumnId);

// 1. Cập nhật cardOrderIds của cột cũ
oldColumn.cardOrderIds = oldColumn.cardOrderIds.filter(id => id !== activeCardId);

// 2. Cập nhật cardOrderIds của cột mới
const newIndex = newColumn.cardOrderIds.indexOf(overCardId);
newColumn.cardOrderIds.splice(newIndex, 0, activeCardId);

// 3. Cập nhật columnId của card
const movedCard = boardState.cards.find(c => c.id === activeCardId);
movedCard.columnId = overColumnId;

